<template>
  <div class="font-Quick h-screen w-full" @wheel="onWheel">
    <SmallNav :currentPath="currentPath" />
    <router-view v-slot="{ Component }">
      <transition :name="animationType">
        <component v-if="show" :is="Component" class="p-16" />
      </transition>
    </router-view>
    <transition :name="animationType">
      <div
        v-if="isNotLastPage"
        class="text-center fixed bottom-2 left-0 right-0"
      >
        <img
          src="@/assets/scroll2.gif"
          @click="afterRoute()"
          class="w-16 m-auto cursor-pointer"
          alt="Scroll page"
        />
      </div>
    </transition>
  </div>
</template>
<script>
import ToBottom from "@/components/transitions/ToBottom.vue";
import SmallNav from "@/components/app/SmallNav.vue";

export default {
  components: {
    ToBottom,
    SmallNav,
  },
  data() {
    return {
      show: false,
      localeChange: true,
      animationType: "slide",
      currentPath: "",
      isNotLastPage: true,
    };
  },
  methods: {
    onWheel(e) {
      let isNos = false;

      e.path.forEach((element) => {
        if (element.id == "nos") {
          isNos = true;
          if (
            element.scrollTop >=
            element.scrollHeight - element.clientHeight
          ) {
            isNos = false;
          } else {
            isNos = true;
          }
          if (element.scrollTop === 0) {
            if (e.deltaY < 0) isNos = false;
          }
        }
      });

      if (!isNos) {
        if (e.deltaY > 0) this.afterRoute();
        if (e.deltaY < 0) this.preRoute();
      }
    },
    afterRoute() {
      const path = this.$router.currentRoute.value.path;
      this.animationType = "slide";

      if (path === "/@/welcome") {
        this.$router.push("/@/about");
      }

      if (path === "/@/about") {
        this.$router.push("/@/skills");
      }

      if (path === "/@/skills") {
        this.$router.push("/@/packages");
      }

      if (path === "/@/packages") {
        this.$router.push("/@/projects");
      }

      if (path === "/@/projects") {
        this.$router.push("/@/education");
      }

      if (path === "/@/education") {
        this.$router.push("/@/employment-history");
      }

      if (path === "/@/education") {
        this.$router.push("/@/employment-history");
      }

      if (path === "/@/employment-history") {
        this.$router.push("/@/social");
      }
    },
    preRoute() {
      const path = this.$router.currentRoute.value.path;
      this.animationType = "preSlide";

      if (path === "/@/about") {
        this.$router.push("/@/welcome");
      }

      if (path === "/@/skills") {
        this.$router.push("/@/about");
      }

      if (path === "/@/packages") {
        this.$router.push("/@/skills");
      }

      if (path === "/@/projects") {
        this.$router.push("/@/packages");
      }

      if (path === "/@/education") {
        this.$router.push("/@/projects");
      }

      if (path === "/@/employment-history") {
        this.$router.push("/@/education");
      }

      if (path === "/@/social") {
        this.$router.push("/@/employment-history");
      }
    },
  },
  mounted() {
    this.show = true;
  },
  created() {
    document.body.style.overflow = "hidden";
  },
  watch: {
    $route(to, from) {
      this.currentPath = this.$router.currentRoute.value.path;
      if (this.currentPath == "/@/social") {
        this.isNotLastPage = false;
      } else {
        this.isNotLastPage = true;
      }
      this.show = false;
      setTimeout(() => (this.show = true), 100);
    },
    "$i18n.locale": function (newVal, oldVal) {
      this.localeChange = false;
      this.show = false;
      setTimeout(() => (this.localeChange = true), 100);
      setTimeout(() => (this.show = true), 100);
    },
  },
};
</script>

<style lang="scss">
body {
  background: rgb(255, 247, 241);
  background: -moz-linear-gradient(
    left,
    rgba(255, 247, 241, 1) 0%,
    rgba(239, 239, 255, 1) 100%
  );
  background: -webkit-linear-gradient(
    left,
    rgba(255, 247, 241, 1) 0%,
    rgba(239, 239, 255, 1) 100%
  );
  background: linear-gradient(
    to right,
    rgba(255, 247, 241, 1) 0%,
    rgba(239, 239, 255, 1) 100%
  );
  filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#fff7f1', endColorstr='#efefff',GradientType=1 ); /* IE6-9 */
}
.mainBg {
  background-color: #82828217;
}

body::-webkit-scrollbar {
  width: 5px;
}

body::-webkit-scrollbar-track {
  background: #f1f1f1;
}

body::-webkit-scrollbar-thumb {
  background: #888;
}

body::-webkit-scrollbar-thumb:hover {
  background: #555;
}
.slide-enter-active,
.slide-leave-active {
  transition: all 1s ease-out;
}

.slide-enter-to {
  position: absolute;
  bottom: 0;
  opacity: 1;
}

.slide-enter-from {
  position: absolute;
  bottom: -100%;
  opacity: 0.3;
}

.slide-leave-to {
  position: absolute;
  top: -100%;
  opacity: 0.3;
}

.slide-leave-from {
  position: absolute;
  top: 0;
  opacity: 1;
}

.preSlide-enter-active,
.preSlide-leave-active {
  transition: all 1s ease-out;
}

.preSlide-enter-to {
  position: absolute;
  top: 0;
  opacity: 1;
}

.preSlide-enter-from {
  position: absolute;
  top: -100%;
  opacity: 0.3;
}

.preSlide-leave-to {
  position: absolute;
  bottom: -100%;
  opacity: 0.3;
}

.preSlide-leave-from {
  position: absolute;
  bottom: 0;
  opacity: 1;
}
</style>
